documents.query:
{
  posts {
    edges {
      node {
        id
        title
        date
        excerpt
      }
    }
  }
}

query PostsAndUsers {
  posts(first: 5) {
    nodes {
      id
      title
      link
      author {
        node {
          id
          name
        }
      }
    }
  }
  users(first: 2) {
    nodes {
      id
      name
      posts(first: 1) {
        nodes {
          id
          title
          link
          author {
            node {
              id
              name
            }
          }
        }
      }
    }
  }
}

query GetPostsWithFragments {
  posts(first: 1) {
    nodes {
      ...post
    }
  }
}

fragment post on Post {
  id
  title
  date
  link
  excerpt
  author {
    node {
      ...author
    }
  }
}

fragment author on User {
  id
  name
  firstName
  lastName
}

query GetPostsWithAliases {
  cardList: posts {
    cards: nodes {
      key: id
      cardTitle: title
      cardDescription: excerpt
    }
  }
}

query PostsAndCategoriesWithAliases {
  list1: posts {
    cards: nodes {
      __typename
      key: id
      title
      description: excerpt
      link
    }
  }
  list2: categories {
    cards: nodes {
      __typename
      key: id
      title: name
      description: description
      link
    }
  }
}

query GetPosts($first: Int) {
  posts(first: $first) {
    nodes {
      id
      title
      link
    }
  }
}

query GetPosts($first: Int, $last: Int, $after: String, $before: String, $where: RootQueryToPostConnectionWhereArgs) {
  posts(first: $first, last: $last, after: $after, before: $before, where: $where) {
    pageInfo {
      hasNextPage
      hasPreviousPage
      startCursor
      endCursor
    }
    edges {
      node {
        id
        title
        link
      }
    }
  }
}

query GetPosts($first: Int, $last: Int, $after: String, $before: String, $where: RootQueryToPostConnectionWhereArgs, $includeField: Boolean!) {
  posts(first: $first, last: $last, after: $after, before: $before, where: $where) {
    pageInfo @include(if: $includeField) {
      hasNextPage
      hasPreviousPage
      startCursor
      endCursor
    }
    edges {
      node {
        id
        title
        link @include(if: $includeField)
      }
    }
  }
}
